```go
package main

import (
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"log"
	"net/http"
	"regexp"
	"strings"
)

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
	MFAToken string `json:"mfa_token"`
}

// SensitiveFields defines fields that should never be logged
var sensitiveFields = []string{"password", "token", "secret", "key", "credential", "mfa"}

// maskSensitiveData redacts sensitive information
func maskSensitiveData(data string) string {
	for _, field := range sensitiveFields {
		pattern := regexp.MustCompile(`(?i)(` + field + `["\s:=]+)[^,}\s"]+`)
		data = pattern.ReplaceAllString(data, "${1}[REDACTED]")
	}
	return data
}

// hashForCorrelation creates a non-reversible hash for log correlation
func hashForCorrelation(data string) string {
	hash := sha256.Sum256([]byte(data))
	return hex.EncodeToString(hash[:8]) // First 8 bytes only
}

func secureLoginHandler(w http.ResponseWriter, r *http.Request) {
	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		log.Printf("[AUTH] Failed to decode login request from IP: %s",
			anonymizeIP(r.RemoteAddr))
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// SECURE: Log only non-sensitive identifiers
	log.Printf("[AUTH] Login attempt - User: %s, IP: %s, UserAgent: %s",
		maskEmail(req.Username),
		anonymizeIP(r.RemoteAddr),
		sanitizeUserAgent(r.UserAgent()))

	if !authenticate(req.Username, req.Password) {
		// SECURE: No credentials in failure logs
		log.Printf("[AUTH] Authentication failed - User: %s, IP: %s, Reason: invalid_credentials",
			maskEmail(req.Username),
			anonymizeIP(r.RemoteAddr))
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	log.Printf("[AUTH] Authentication successful - User: %s, IP: %s",
		maskEmail(req.Username),
		anonymizeIP(r.RemoteAddr))
	w.WriteHeader(http.StatusOK)
}

// maskEmail partially masks email addresses
func maskEmail(email string) string {
	parts := strings.Split(email, "@")
	if len(parts) != 2 {
		return "[INVALID_EMAIL]"
	}
	local := parts[0]
	if len(local) > 2 {
		return local[:2] + "***@" + parts[1]
	}
	return "***@" + parts[1]
}

// anonymizeIP masks the last octet of IPv4 addresses
func anonymizeIP(ip string) string {
	parts := strings.Split(strings.Split(ip, ":")[0], ".")
	if len(parts) == 4 {
		return parts[0] + "." + parts[1] + "." + parts[2] + ".xxx"
	}
	return "[ANONYMIZED]"
}

// sanitizeUserAgent truncates and removes potentially dangerous content
func sanitizeUserAgent(ua string) string {
	if len(ua) > 100 {
		ua = ua[:100]
	}
	return strings.ReplaceAll(ua, "\n", "")
}

func authenticate(username, password string) bool {
	return username == "admin" && password == "secret123"
}
