**Key Security Controls**:
- **Data Masking**: Email addresses and IPs are partially masked to prevent direct identification while maintaining correlation ability
- **No Credentials Logged**: Passwords, MFA tokens, and API keys are never written to logs
- **Structured Logging**: Consistent format with category tags ([AUTH]) enables efficient log analysis
- **Input Sanitization**: User-controlled data like UserAgent is sanitized before logging

This is a common challenge - you need visibility for debugging but can't expose sensitive data. The solution is implementing a multi-tier logging system with automatic sensitive data detection and redaction, combined with secure debug modes that have strict access controls.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"io"
	"log/slog"
	"net/http"
	"os"
	"regexp"
	"strings"
	"sync"
	"time"
)

// LogLevel controls logging verbosity
type LogLevel int

const (
	LogLevelProduction LogLevel = iota
	LogLevelDebug
	LogLevelTrace
)

// SensitiveFieldPatterns defines patterns for sensitive data
var sensitiveFieldPatterns = []*regexp.Regexp{
	regexp.MustCompile(`(?i)(password|passwd|pwd)["\s:=]+[^,}\s"]+`),
	regexp.MustCompile(`(?i)(token|bearer|jwt)["\s:=]+[^,}\s"]+`),
	regexp.MustCompile(`(?i)(api[_-]?key|apikey)["\s:=]+[^,}\s"]+`),
	regexp.MustCompile(`(?i)(secret|private[_-]?key)["\s:=]+[^,}\s"]+`),
	regexp.MustCompile(`(?i)(ssn|social[_-]?security)["\s:=]+[^,}\s"]+`),
	regexp.MustCompile(`(?i)(credit[_-]?card|card[_-]?number|cvv|cvc)["\s:=]+[^,}\s"]+`),
	regexp.MustCompile(`(?i)(auth|authorization)["\s:=]+[^,}\s"]+`),
	regexp.MustCompile(`\b[0-9]{13,16}\b`), // Credit card numbers
	regexp.MustCompile(`\b[0-9]{3}-[0-9]{2}-[0-9]{4}\b`), // SSN
}

// SecureLogger provides safe logging with automatic redaction
type SecureLogger struct {
	logger      *slog.Logger
	level       LogLevel
	redactCache sync.Map
	auditLog    *slog.Logger
}

// NewSecureLogger creates a production-ready logger
func NewSecureLogger(level LogLevel) *SecureLogger {
	// Main application logger
	mainHandler := slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
		ReplaceAttr: func(groups []string, a slog.Attr) slog.Attr {
			// Automatically redact any field with sensitive names
			key := strings.ToLower(a.Key)
			for _, sensitive := range []string{"password", "token", "secret", "key", "auth"} {
				if strings.Contains(key, sensitive) {
					return slog.String(a.Key, "[REDACTED]")
				}
			}
			return a
		},
	})

	// Separate audit log for security events
	auditFile, _ := os.OpenFile("/var/log/app/audit.log",
		os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0600)
	auditHandler := slog.NewJSONHandler(auditFile, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	})

	return &SecureLogger{
		logger:   slog.New(mainHandler),
		level:    level,
		auditLog: slog.New(auditHandler),
	}
}

// RedactSensitiveData removes sensitive information from strings
func (sl *SecureLogger) RedactSensitiveData(data string) string {
	// Check cache first for performance
	if cached, ok := sl.redactCache.Load(data); ok {
		return cached.(string)
	}

	redacted := data
	for _, pattern := range sensitiveFieldPatterns {
		redacted = pattern.ReplaceAllStringFunc(redacted, func(match string) string {
			// Preserve field name but redact value
			parts := strings.SplitN(match, ":", 2)
			if len(parts) == 2 {
				return parts[0] + ": [REDACTED]"
			}
			return "[REDACTED]"
		})
	}

	// Cache result (limit cache size in production)
	sl.redactCache.Store(data, redacted)
	return redacted
}

// LogRequest safely logs HTTP request details
func (sl *SecureLogger) LogRequest(ctx context.Context, r *http.Request, body []byte) {
	requestID := generateRequestID()
	ctx = context.WithValue(ctx, "request_id", requestID)

	// Always log basic request info
	sl.logger.InfoContext(ctx, "incoming_request",
		slog.String("request_id", requestID),
		slog.String("method", r.Method),
		slog.String("path", r.URL.Path),
		slog.String("remote_addr", anonymizeIP(r.RemoteAddr)),
		slog.String("user_agent", truncate(r.UserAgent(), 100)),
	)

	// Debug level: Log redacted headers
	if sl.level >= LogLevelDebug {
		safeHeaders := sl.redactHeaders(r.Header)
		sl.logger.DebugContext(ctx, "request_headers",
			slog.String("request_id", requestID),
			slog.Any("headers", safeHeaders),
		)
	}

	// Trace level: Log redacted body (ONLY in non-production)
	if sl.level >= LogLevelTrace && os.Getenv("APP_ENV") != "production" {
		redactedBody := sl.RedactSensitiveData(string(body))
		sl.logger.DebugContext(ctx, "request_body",
			slog.String("request_id", requestID),
			slog.String("body", truncate(redactedBody, 1000)),
		)
	}
}

// redactHeaders removes sensitive header values
func (sl *SecureLogger) redactHeaders(headers http.Header) map[string]string {
	sensitiveHeaders := map[string]bool{
		"authorization": true,
		"cookie":        true,
		"x-api-key":     true,
		"x-auth-token":  true,
		"proxy-authorization": true,
	}

	safe := make(map[string]string)
	for key, values := range headers {
		lowerKey := strings.ToLower(key)
		if sensitiveHeaders[lowerKey] {
			safe[key] = "[REDACTED]"
		} else {
			safe[key] = strings.Join(values, ", ")
		}
	}
	return safe
}

// LogAuthEvent logs authentication events to audit log
func (sl *SecureLogger) LogAuthEvent(ctx context.Context, eventType string, username string, success bool, metadata map[string]string) {
	requestID, _ := ctx.Value("request_id").(string)

	// Main log: minimal info
	sl.logger.InfoContext(ctx, "auth_event",
		slog.String("request_id", requestID),
		slog.String("event", eventType),
		slog.String("user", maskIdentifier(username)),
		slog.Bool("success", success),
	)

	// Audit log: more detail for compliance (still no credentials)
	sl.auditLog.InfoContext(ctx, "auth_audit",
		slog.String("request_id", requestID),
		slog.String("event", eventType),
		slog.String("user", username), // Full username OK in restricted audit log
		slog.Bool("success", success),
		slog.Time("timestamp", time.Now().UTC()),
		slog.Any("metadata", redactMap(metadata)),
	)
}

// LoggingMiddleware wraps handlers with secure logging
func (sl *SecureLogger) LoggingMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		requestID := generateRequestID()
		ctx := context.WithValue(r.Context(), "request_id", requestID)

		// Read and restore body
		var bodyBytes []byte
		if r.Body != nil {
			bodyBytes, _ = io.ReadAll(io.LimitReader(r.Body, 10000)) // Limit body size
			r.Body = io.NopCloser(bytes.NewBuffer(bodyBytes))
		}

		sl.LogRequest(ctx, r, bodyBytes)

		// Wrap response writer to capture status
		wrapped := &responseWrapper{ResponseWriter: w, status: 200}
		next.ServeHTTP(wrapped, r.WithContext(ctx))

		// Log response (no body to avoid leaking sensitive response data)
		sl.logger.InfoContext(ctx, "response",
			slog.String("request_id", requestID),
			slog.Int("status", wrapped.status),
			slog.Duration("duration", time.Since(start)),
		)
	})
}

type responseWrapper struct {
	http.ResponseWriter
	status int
}

func (rw *responseWrapper) WriteHeader(code int) {
	rw.status = code
	rw.ResponseWriter.WriteHeader(code)
}

// Helper functions
func generateRequestID() string {
	b := make([]byte, 8)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func anonymizeIP(ip string) string {
	parts := strings.Split(strings.Split(ip, ":")[0], ".")
	if len(parts) == 4 {
		return parts[0] + "." + parts[1] + ".xxx.xxx"
	}
	return "[ANONYMIZED]"
}

func maskIdentifier(id string) string {
	if len(id) <= 4 {
		return "****"
	}
	return id[:2] + "****" + id[len(id)-2:]
}

func truncate(s string, maxLen int) string {
	if len(s) > maxLen {
		return s[:maxLen] + "...[TRUNCATED]"
	}
	return s
}

func redactMap(m map[string]string) map[string]string {
	safe := make(map[string]string)
	for k, v := range m {
		lower := strings.ToLower(k)
		if strings.Contains(lower, "password") || strings.Contains(lower, "token") ||
			strings.Contains(lower, "secret") || strings.Contains(lower, "key") {
			safe[k] = "[REDACTED]"
		} else {
			safe[k] = v
		}
	}
	return safe
}

func main() {
	logLevel := LogLevelProduction
	if os.Getenv("APP_ENV") == "development" {
		logLevel = LogLevelDebug
	}

	logger := NewSecureLogger(logLevel)

	mux := http.NewServeMux()
	mux.HandleFunc("/api/login", func(w http.ResponseWriter, r *http.Request) {
		var req struct {
			Username string `json:"username"`
			Password string `json:"password"`
		}
		json.NewDecoder(r.Body).Decode(&req)

		logger.LogAuthEvent(r.Context(), "login_attempt", req.Username, true,
			map[string]string{"method": "password", "ip": r.RemoteAddr})

		w.WriteHeader(http.StatusOK)
	})

	http.ListenAndServe(":8080", logger.LoggingMiddleware(mux))
}
```

**Defense in Depth Layers**:

1. **Attribute-Level Redaction**: slog's ReplaceAttr automatically redacts fields with sensitive names
```go
ReplaceAttr: func(groups []string, a slog.Attr) slog.Attr {
    if strings.Contains(strings.ToLower(a.Key), "password") {
        return slog.String(a.Key, "[REDACTED]")
    }
    return a
}
```

2. **Pattern-Based Redaction**: Regex patterns catch sensitive data in string content
```go
regexp.MustCompile(`(?i)(password|token)["\s:=]+[^,}\s"]+`)
```

3. **Tiered Logging Levels**: Production only logs essentials; debug modes require explicit environment flags
```go
if sl.level >= LogLevelTrace && os.Getenv("APP_ENV") != "production" {
    // Only then log redacted body
}
```

**Additional Protections**:
- **Separate Audit Log**: Security events go to a restricted audit log with tighter access controls (0600 permissions)
- **Request ID Correlation**: Unique IDs allow tracing without logging sensitive identifiers
- **Body Size Limits**: Prevent log injection and DoS via `io.LimitReader(r.Body, 10000)`
- **IP Anonymization**: GDPR compliance by masking last two octets in general logs
- **Header Filtering**: Authorization, Cookie, and API key headers are always redacted
- **Cache for Performance**: Redaction results cached to minimize regex overhead on high-traffic endpoints
- **Structured JSON Logging**: Enables secure log aggregation and SIEM integration without string parsing risks

Logging complex objects and API responses is a common need for debugging, but it's also where most sensitive data leakage occurs. You need a structured approach with automatic sanitization.

**PRODUCTION PATTERN**:

```python
import logging
import json
import re
import hashlib
from typing import Any, Dict, List, Set, Optional, Union
from dataclasses import dataclass, field
from functools import wraps
from flask import Flask, request, g
import time
import os

app = Flask(__name__)

@dataclass
class LogSanitizer:
    """Production-grade log sanitizer for complex objects."""

    # Fields to completely remove from logs
    REDACT_FIELDS: Set[str] = field(default_factory=lambda: {
        'password', 'passwd', 'pwd', 'secret', 'token', 'api_key',
        'apikey', 'access_token', 'refresh_token', 'private_key',
        'credit_card', 'card_number', 'cvv', 'ssn', 'social_security',
        'pin', 'otp', 'mfa_code', 'auth_code', 'session_id',
        'cookie', 'authorization', 'x-api-key', 'bearer'
    })

    # Fields to partially mask (show first/last chars)
    MASK_FIELDS: Set[str] = field(default_factory=lambda: {
        'email', 'phone', 'address', 'name', 'username', 'user_id',
        'account_number', 'ip_address', 'device_id'
    })

    # Regex patterns for detecting sensitive data in values
    SENSITIVE_PATTERNS: List[tuple] = field(default_factory=lambda: [
        (re.compile(r'\b\d{13,16}\b'), '***CARD***'),  # Credit cards
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '***SSN***'),  # US SSN
        (re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'), '***EMAIL***'),
        (re.compile(r'eyJ[A-Za-z0-9_-]*\.[A-Za-z0-9_-]*\.[A-Za-z0-9_-]*'), '***JWT***'),  # JWT tokens
        (re.compile(r'\b(?:password|secret|key)\s*[=:]\s*\S+', re.I), '***CREDENTIAL***'),
    ])

    max_depth: int = 10
    max_string_length: int = 500

    def sanitize(self, obj: Any, depth: int = 0) -> Any:
        """Recursively sanitize object for safe logging."""
        if depth > self.max_depth:
            return '***MAX_DEPTH_EXCEEDED***'

        if obj is None:
            return None
        elif isinstance(obj, bool):
            return obj
        elif isinstance(obj, (int, float)):
            return obj
        elif isinstance(obj, str):
            return self._sanitize_string(obj)
        elif isinstance(obj, dict):
            return self._sanitize_dict(obj, depth)
        elif isinstance(obj, (list, tuple)):
            return [self.sanitize(item, depth + 1) for item in obj[:100]]  # Limit array size
        else:
            # Handle custom objects
            try:
                return self.sanitize(obj.__dict__, depth)
            except AttributeError:
                return str(type(obj).__name__)

    def _sanitize_string(self, value: str) -> str:
        """Sanitize string values."""
        if len(value) > self.max_string_length:
            value = value[:self.max_string_length] + '***TRUNCATED***'

        for pattern, replacement in self.SENSITIVE_PATTERNS:
            value = pattern.sub(replacement, value)

        return value

    def _sanitize_dict(self, obj: Dict, depth: int) -> Dict:
        """Sanitize dictionary keys and values."""
        result = {}
        for key, value in obj.items():
            key_lower = str(key).lower().replace('-', '_').replace(' ', '_')

            if key_lower in self.REDACT_FIELDS:
                result[key] = '***REDACTED***'
            elif key_lower in self.MASK_FIELDS:
                result[key] = self._mask_value(value)
            else:
                result[key] = self.sanitize(value, depth + 1)

        return result

    def _mask_value(self, value: Any) -> str:
        """Partially mask a value, preserving some chars for debugging."""
        if value is None:
            return None
        str_value = str(value)
        if len(str_value) <= 4:
            return '***'
        return str_value[:2] + '*' * (len(str_value) - 4) + str_value[-2:]


class SecureJSONFormatter(logging.Formatter):
    """JSON formatter with automatic sanitization."""

    def __init__(self, sanitizer: LogSanitizer):
        super().__init__()
        self.sanitizer = sanitizer

    def format(self, record: logging.LogRecord) -> str:
        log_data = {
            'timestamp': self.formatTime(record),
            'level': record.levelname,
            'logger': record.name,
            'message': record.getMessage(),
            'request_id': getattr(g, 'request_id', 'N/A'),
        }

        # Sanitize any extra data attached to the log record
        if hasattr(record, 'extra_data'):
            log_data['data'] = self.sanitizer.sanitize(record.extra_data)

        if record.exc_info:
            log_data['exception'] = self.formatException(record.exc_info)

        return json.dumps(log_data)


class SecureLogger:
    """Production-ready secure logger wrapper."""

    def __init__(self, name: str):
        self.logger = logging.getLogger(name)
        self.sanitizer = LogSanitizer()

        # Configure handler based on environment
        if os.getenv('FLASK_ENV') == 'production':
            handler = logging.FileHandler('/var/log/app/secure.log')
            handler.setFormatter(SecureJSONFormatter(self.sanitizer))
            self.logger.addHandler(handler)
            self.logger.setLevel(logging.INFO)
        else:
            handler = logging.StreamHandler()
            handler.setFormatter(SecureJSONFormatter(self.sanitizer))
            self.logger.addHandler(handler)
            self.logger.setLevel(logging.DEBUG)

    def info(self, message: str, data: Any = None):
        record = self.logger.makeRecord(
            self.logger.name, logging.INFO, '', 0, message, (), None
        )
        if data:
            record.extra_data = data
        self.logger.handle(record)

    def warning(self, message: str, data: Any = None):
        record = self.logger.makeRecord(
            self.logger.name, logging.WARNING, '', 0, message, (), None
        )
        if data:
            record.extra_data = data
        self.logger.handle(record)

    def error(self, message: str, data: Any = None, exc_info: bool = False):
        self.logger.error(message, exc_info=exc_info)


secure_log = SecureLogger(__name__)


def audit_log(action: str):
    """Decorator for automatic audit logging of endpoints."""
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            g.request_id = hashlib.sha256(
                f"{time.time()}-{request.remote_addr}".encode()
            ).hexdigest()[:16]

            start_time = time.time()

            # Log request (sanitized)
            secure_log.info(f"API Request: {action}", {
                'method': request.method,
                'path': request.path,
                'query_params': dict(request.args),
                'body': request.get_json(silent=True),
                'headers': dict(request.headers),
            })

            try:
                response = f(*args, **kwargs)
                duration = time.time() - start_time

                # Log response (sanitized)
                secure_log.info(f"API Response: {action}", {
                    'status': response.status_code if hasattr(response, 'status_code') else 200,
                    'duration_ms': round(duration * 1000, 2),
                })

                return response
            except Exception as e:
                secure_log.error(f"API Error: {action}", {
                    'error_type': type(e).__name__,
                    'error_message': str(e),
                }, exc_info=True)
                raise

        return wrapper
    return decorator


@app.route('/api/user/<int:user_id>', methods=['GET'])
