def get_user(user_id: int):
    """Example endpoint with secure logging."""
    user = fetch_user_from_db(user_id)

    # Safe to log - sanitizer will handle sensitive fields
    secure_log.info("User retrieved", {'user': user})

    return jsonify(user)


@app.route('/api/payment', methods=['POST'])
