def process_payment():
    """Payment endpoint demonstrating PCI-compliant logging."""
    payment_data = request.get_json()

    # Even if developer accidentally logs full payment data,
    # the sanitizer will redact credit_card, cvv, etc.
    secure_log.info("Payment processing initiated", payment_data)

    result = process_payment_gateway(payment_data)

    secure_log.info("Payment completed", {
        'transaction_id': result.get('transaction_id'),
        'status': result.get('status'),
        'amount': result.get('amount'),
    })

    return jsonify({'status': 'success'})
