  if (user) {
    const token = generateJWT(user);
    // VULNERABLE: Logging the session token
    logger.info(`Login successful for ${username}, token: ${token}`);
    res.json({ success: true, token: token });
  } else {
    // VULNERABLE: Logging failed attempt with password
    logger.warn(`Failed login for ${username} with password ${password}`);
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

function authenticateUser(username, password) {
  // Simulated auth
  return username === 'admin' ? { id: 1, username } : null;
}

