function requestLoggingMiddleware(req, res, next) {
  const correlationId = req.headers['x-correlation-id'] || 
                        crypto.randomUUID();
  const startTime = Date.now();

  // Attach to request for use in handlers
  req.correlationId = correlationId;
  req.startTime = startTime;

  // Log sanitized request
  logger.info('Incoming request', {
    correlationId,
    method: req.method,
    path: req.path,
    query: sanitizer.sanitizeObject(req.query),
    body: req.body ? sanitizer.sanitizeObject(req.body) : undefined,
    headers: sanitizer.sanitizeHeaders(req.headers),
    clientIp: req.ip,
    userAgent: req.get('User-Agent')
  });

  // Capture response
  const originalSend = res.send;
  res.send = function(body) {
    const duration = Date.now() - startTime;

    let responseBody;
    try {
      responseBody = typeof body === 'string' ? JSON.parse(body) : body;
      responseBody = sanitizer.sanitizeObject(responseBody);
    } catch (e) {
      responseBody = '[NON-JSON RESPONSE]';
    }

    logger.info('Outgoing response', {
      correlationId,
      statusCode: res.statusCode,
      duration: `${duration}ms`,
      responseBody: res.statusCode < 400 ? responseBody : undefined,
      contentLength: body ? body.length : 0
    });

    return originalSend.call(this, body);
  };

  next();
}

