**Additional Protections**:
- **Log injection prevention**: All newlines and control characters stripped to prevent log forging
- **Truncation limits**: Messages capped at 10KB to prevent log flooding DoS
- **Structured audit logging**: Security events use JSON format for SIEM integration
- **Exception sanitization**: Stack traces limited to 10 frames, messages scrubbed
- **Collection size limits**: Arrays/lists truncated to prevent memory exhaustion

Authentication logging is critical for security monitoring, but it's extremely easy to accidentally log sensitive data like passwords, tokens, or PII. This was the exact mistake Twitter made in 2018, exposing 330 million passwords in their internal logs.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"log"
	"net/http"
	"time"
)

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
	MFAToken string `json:"mfa_token,omitempty"`
}

type User struct {
	ID           int
	Username     string
	Email        string
	SSN          string
	PasswordHash string
}

func handleLogin(w http.ResponseWriter, r *http.Request) {
	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		log.Printf("Failed to parse login request: %v", err)
		http.Error(w, "Bad request", http.StatusBadRequest)
		return
	}

	// VULNERABLE: Logging the entire request including password
	log.Printf("Login attempt - User: %s, Password: %s, MFA: %s, IP: %s",
		req.Username, req.Password, req.MFAToken, r.RemoteAddr)

	user, err := authenticateUser(req.Username, req.Password)
	if err != nil {
		// VULNERABLE: Logging credentials on failure
		log.Printf("Authentication failed for user %s with password %s: %v",
			req.Username, req.Password, err)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	// VULNERABLE: Logging sensitive user data
	log.Printf("User authenticated: %+v", user)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
