func authenticateUser(username, password string) (*User, error) {
	// Simulated authentication
	return &User{
		ID:           1,
		Username:     username,
		Email:        "user@example.com",
		SSN:          "123-45-6789",
		PasswordHash: "$2a$10$...",
	}, nil
