**Why This Is Dangerous**:
- Passwords stored in plaintext in log files, log aggregators, and backups
- SSN and PII exposed to anyone with log access (developers, ops, attackers)
- MFA tokens logged, potentially allowing replay attacks
- Password hashes in logs help attackers crack passwords offline
- Violates GDPR, PCI-DSS, HIPAA, and most compliance frameworks

**SECURE VERSION**:

```go
package main

import (
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"log/slog"
	"net/http"
	"os"
	"time"
)

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
	MFAToken string `json:"mfa_token,omitempty"`
}

type User struct {
	ID           int
	Username     string
	Email        string
	SSN          string
	PasswordHash string
}

// SafeUser contains only non-sensitive data for logging
type SafeUser struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
}

var logger *slog.Logger

func init() {
	// Structured logging with JSON output for production
	logger = slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))
}

// maskEmail partially masks email for logging
func maskEmail(email string) string {
	if len(email) < 5 {
		return "***@***"
	}
	return email[:2] + "***" + email[len(email)-4:]
}

// generateRequestID creates a unique identifier for request correlation
func generateRequestID(username, ip string, timestamp time.Time) string {
	data := username + ip + timestamp.String()
	hash := sha256.Sum256([]byte(data))
	return hex.EncodeToString(hash[:8])
}

// toSafeUser creates a logging-safe representation
func (u *User) toSafeUser() SafeUser {
	return SafeUser{
		ID:       u.ID,
		Username: u.Username,
	}
}

func handleLoginSecure(w http.ResponseWriter, r *http.Request) {
	timestamp := time.Now()
	clientIP := r.RemoteAddr

	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		logger.Warn("Failed to parse login request",
			slog.String("ip", clientIP),
			slog.String("error", err.Error()),
		)
		http.Error(w, "Bad request", http.StatusBadRequest)
		return
	}

	requestID := generateRequestID(req.Username, clientIP, timestamp)

	// SECURE: Log only non-sensitive authentication metadata
	logger.Info("Login attempt",
		slog.String("request_id", requestID),
		slog.String("username", req.Username),
		slog.String("ip", clientIP),
		slog.Bool("mfa_provided", req.MFAToken != ""),
		slog.String("user_agent", r.UserAgent()),
	)

	user, err := authenticateUser(req.Username, req.Password)
	if err != nil {
		// SECURE: Never log passwords or tokens on failure
		logger.Warn("Authentication failed",
			slog.String("request_id", requestID),
			slog.String("username", req.Username),
			slog.String("ip", clientIP),
			slog.String("reason", "invalid_credentials"),
		)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	// SECURE: Log only safe user representation
	logger.Info("Authentication successful",
		slog.String("request_id", requestID),
		slog.Int("user_id", user.toSafeUser().ID),
		slog.String("username", user.toSafeUser().Username),
		slog.String("ip", clientIP),
	)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
}

func authenticateUser(username, password string) (*User, error) {
	return &User{
		ID:           1,
		Username:     username,
		Email:        "user@example.com",
		SSN:          "123-45-6789",
		PasswordHash: "$2a$10$...",
	}, nil
}
```

**Key Security Controls**:
- **Never log credentials**: Passwords, tokens, API keys are completely excluded from logs
- **Safe data projections**: Use dedicated structs (SafeUser) that only contain loggable fields
- **Structured logging**: Use slog for consistent, parseable log format
- **Request correlation**: Generate unique request IDs for tracing without exposing sensitive data
- **Metadata only**: Log boolean indicators (mfa_provided: true) instead of actual values

Great questions! Environment-aware logging and controlling third-party library output are essential for production security. You need a comprehensive approach that sanitizes data automatically and controls all log sources.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"io"
	"log/slog"
	"net/http"
	"os"
	"regexp"
	"strings"
	"sync"
	"time"
)

// SensitiveFields defines fields that must be redacted
var sensitiveFields = map[string]bool{
	"password":       true,
	"passwd":         true,
	"secret":         true,
	"token":          true,
	"api_key":        true,
	"apikey":         true,
	"authorization":  true,
	"credit_card":    true,
	"creditcard":     true,
	"ssn":            true,
	"social_security": true,
	"cvv":            true,
	"pin":            true,
	"mfa_token":      true,
	"otp":            true,
	"private_key":    true,
}

// Patterns for sensitive data detection
var sensitivePatterns = []*regexp.Regexp{
	regexp.MustCompile(`(?i)password["']?\s*[:=]\s*["']?[^"'\s,}]+`),
	regexp.MustCompile(`(?i)bearer\s+[a-zA-Z0-9\-_\.]+`),
	regexp.MustCompile(`\b\d{3}-\d{2}-\d{4}\b`),                    // SSN
	regexp.MustCompile(`\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b`), // Credit card
	regexp.MustCompile(`(?i)api[_-]?key["']?\s*[:=]\s*["']?[^"'\s,}]+`),
}

// Environment configuration
type LogConfig struct {
	Environment      string // "development", "staging", "production"
	LogLevel         slog.Level
	RedactSensitive  bool
	LogRequestBodies bool
	MaxBodyLogSize   int
}

func NewLogConfig() *LogConfig {
	env := os.Getenv("APP_ENV")
	if env == "" {
		env = "production" // Safe default
	}

	config := &LogConfig{
		Environment:     env,
		RedactSensitive: true, // Always true by default
		MaxBodyLogSize:  1024,
	}

	switch env {
	case "development":
		config.LogLevel = slog.LevelDebug
		config.LogRequestBodies = true
	case "staging":
		config.LogLevel = slog.LevelInfo
		config.LogRequestBodies = true
	case "production":
		config.LogLevel = slog.LevelInfo
		config.LogRequestBodies = false
		config.RedactSensitive = true // Enforce in production
	}

	return config
}

// SanitizingHandler wraps slog.Handler to automatically redact sensitive data
type SanitizingHandler struct {
	inner  slog.Handler
	config *LogConfig
	mu     sync.RWMutex
}

func NewSanitizingHandler(inner slog.Handler, config *LogConfig) *SanitizingHandler {
	return &SanitizingHandler{
		inner:  inner,
		config: config,
	}
}

func (h *SanitizingHandler) Enabled(ctx context.Context, level slog.Level) bool {
	return h.inner.Enabled(ctx, level)
}

func (h *SanitizingHandler) Handle(ctx context.Context, r slog.Record) error {
	if !h.config.RedactSensitive {
		return h.inner.Handle(ctx, r)
	}

	// Create new record with sanitized attributes
	newRecord := slog.NewRecord(r.Time, r.Level, h.sanitizeString(r.Message), r.PC)

	r.Attrs(func(a slog.Attr) bool {
		newRecord.AddAttrs(h.sanitizeAttr(a))
		return true
	})

	return h.inner.Handle(ctx, newRecord)
}

func (h *SanitizingHandler) WithAttrs(attrs []slog.Attr) slog.Handler {
	sanitized := make([]slog.Attr, len(attrs))
	for i, a := range attrs {
		sanitized[i] = h.sanitizeAttr(a)
	}
	return &SanitizingHandler{
		inner:  h.inner.WithAttrs(sanitized),
		config: h.config,
	}
}

func (h *SanitizingHandler) WithGroup(name string) slog.Handler {
	return &SanitizingHandler{
		inner:  h.inner.WithGroup(name),
		config: h.config,
	}
}

func (h *SanitizingHandler) sanitizeAttr(a slog.Attr) slog.Attr {
	key := strings.ToLower(a.Key)

	// Check if field name indicates sensitive data
	if sensitiveFields[key] {
		return slog.String(a.Key, "[REDACTED]")
	}

	// For string values, check content patterns
	if a.Value.Kind() == slog.KindString {
		return slog.String(a.Key, h.sanitizeString(a.Value.String()))
	}

	// Handle nested groups
	if a.Value.Kind() == slog.KindGroup {
		attrs := a.Value.Group()
		sanitized := make([]slog.Attr, len(attrs))
		for i, attr := range attrs {
			sanitized[i] = h.sanitizeAttr(attr)
		}
		return slog.Group(a.Key, any(sanitized).([]any)...)
	}

	return a
}

func (h *SanitizingHandler) sanitizeString(s string) string {
	result := s
	for _, pattern := range sensitivePatterns {
		result = pattern.ReplaceAllString(result, "[REDACTED]")
	}
	return result
}

// SecureLogger provides environment-aware logging
type SecureLogger struct {
	logger *slog.Logger
	config *LogConfig
}

func NewSecureLogger(config *LogConfig) *SecureLogger {
	var handler slog.Handler

	jsonHandler := slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: config.LogLevel,
	})

	handler = NewSanitizingHandler(jsonHandler, config)

	return &SecureLogger{
		logger: slog.New(handler),
		config: config,
	}
}

// LogRequest safely logs HTTP request details
func (sl *SecureLogger) LogRequest(r *http.Request, requestID string) {
	attrs := []slog.Attr{
		slog.String("request_id", requestID),
		slog.String("method", r.Method),
		slog.String("path", r.URL.Path),
		slog.String("remote_addr", r.RemoteAddr),
		slog.String("user_agent", r.UserAgent()),
	}

	// Only log sanitized headers
	safeHeaders := sl.sanitizeHeaders(r.Header)
	attrs = append(attrs, slog.Any("headers", safeHeaders))

	// Conditionally log request body in non-production
	if sl.config.LogRequestBodies && r.Body != nil {
		body, err := io.ReadAll(io.LimitReader(r.Body, int64(sl.config.MaxBodyLogSize)))
		if err == nil {
			sanitizedBody := sl.sanitizeJSON(string(body))
			attrs = append(attrs, slog.String("body", sanitizedBody))
		}
	}

	sl.logger.LogAttrs(context.Background(), slog.LevelInfo, "HTTP Request", attrs...)
}

func (sl *SecureLogger) sanitizeHeaders(headers http.Header) map[string]string {
	safe := make(map[string]string)
	sensitiveHeaders := map[string]bool{
		"authorization": true,
		"cookie":        true,
		"x-api-key":     true,
		"x-auth-token":  true,
	}

	for key, values := range headers {
		lowerKey := strings.ToLower(key)
		if sensitiveHeaders[lowerKey] {
			safe[key] = "[REDACTED]"
		} else {
			safe[key] = strings.Join(values, ", ")
		}
	}
	return safe
}

func (sl *SecureLogger) sanitizeJSON(jsonStr string) string {
	var data map[string]interface{}
	if err := json.Unmarshal([]byte(jsonStr), &data); err != nil {
		return "[INVALID_JSON]"
	}

	sl.sanitizeMap(data)

	result, _ := json.Marshal(data)
	return string(result)
}

func (sl *SecureLogger) sanitizeMap(data map[string]interface{}) {
	for key, value := range data {
		lowerKey := strings.ToLower(key)
		if sensitiveFields[lowerKey] {
			data[key] = "[REDACTED]"
			continue
		}

		if nested, ok := value.(map[string]interface{}); ok {
			sl.sanitizeMap(nested)
		}
	}
}

// ThirdPartyLogCapture redirects standard library logs through sanitization
type ThirdPartyLogCapture struct {
	logger *SecureLogger
}

func (c *ThirdPartyLogCapture) Write(p []byte) (n int, err error) {
	message := strings.TrimSpace(string(p))
	// Route through sanitizing logger
	c.logger.logger.Info("third_party_log",
		slog.String("source", "stdlib"),
		slog.String("message", message),
	)
	return len(p), nil
}

// AuditLogger for security events with tamper detection
type AuditLogger struct {
	logger *slog.Logger
}

func NewAuditLogger() *AuditLogger {
	// Audit logs go to separate destination (could be SIEM)
	handler := slog.NewJSONHandler(os.Stderr, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	})

	return &AuditLogger{
		logger: slog.New(handler),
	}
}

func (al *AuditLogger) LogSecurityEvent(eventType string, userID int, details map[string]string) {
	// Sanitize details before logging
	safeDetails := make(map[string]string)
	for k, v := range details {
		if sensitiveFields[strings.ToLower(k)] {
			safeDetails[k] = "[REDACTED]"
		} else {
			safeDetails[k] = v
		}
	}

	al.logger.Info("security_event",
		slog.String("event_type", eventType),
		slog.Int("user_id", userID),
		slog.Time("timestamp", time.Now().UTC()),
		slog.Any("details", safeDetails),
	)
}

func main() {
	config := NewLogConfig()
	secureLogger := NewSecureLogger(config)

	// Capture third-party library logs
	import "log"
	log.SetOutput(&ThirdPartyLogCapture{logger: secureLogger})

	// Example usage
	http.HandleFunc("/api/login", func(w http.ResponseWriter, r *http.Request) {
		requestID := generateRequestID()
		secureLogger.LogRequest(r, requestID)

		// Your handler logic...
		w.WriteHeader(http.StatusOK)
	})

	http.ListenAndServe(":8080", nil)
}

func generateRequestID() string {
	return time.Now().Format("20060102150405") + "-" + "abc123"
}
```

**Defense in Depth Layers**:

1. **Field-level sanitization**: Automatic redaction based on field names
